package com.example.kafkastreaming.producer;

import java.time.Instant;
import java.util.UUID;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

@Service
public class EventProducer {

    private final KafkaTemplate<String, String> kafkaTemplate;
    private final String topic;

    public EventProducer(
            KafkaTemplate<String, String> kafkaTemplate,
            @Value("${app.kafka.topic:events}") String topic
    ) {
        this.kafkaTemplate = kafkaTemplate;
        this.topic = topic;
    }

    public void publish(String eventType, String payload) {
        String key = eventType + ":" + UUID.randomUUID();
        String value = "{\"id\":\"" + UUID.randomUUID() + "\",\"type\":\"" + escape(eventType) + "\",\"ts\":\"" + Instant.now() + "\",\"payload\":\"" + escape(payload) + "\"}";
        kafkaTemplate.send(topic, key, value);
    }

    private String escape(String s) {
        if (s == null) return "";
        return s.replace("\\", "\\\\").replace("\"", "\\\"");
    }
}

package com.example.kafkastreaming.consumer;

import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Component;

@Component
public class EventConsumer {

    @KafkaListener(
            topics = "${app.kafka.topic:events}",
            groupId = "${app.kafka.consumer.group-id:event-streaming-platform}"
    )
    public void onMessage(ConsumerRecord<String, String> record) {
        String key = record.key();
        String value = record.value();
        int partition = record.partition();
        long offset = record.offset();

        System.out.println("Consumed event: key=" + key + " partition=" + partition + " offset=" + offset + " value=" + value);
    }
}

package com.example.kafkastreaming.web;

import com.example.kafkastreaming.producer.EventProducer;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/events")
public class EventController {

    private final EventProducer producer;

    public EventController(EventProducer producer) {
        this.producer = producer;
    }

    @PostMapping
    public ResponseEntity<Void> publish(
            @RequestParam(defaultValue = "generic") String type,
            @RequestBody(required = false) String payload
    ) {
        producer.publish(type, payload == null ? "" : payload);
        return ResponseEntity.accepted().build();
    }
}

